B.XS=new A.l(2000,1,30,"\uc815\uce58 \uc9c0\ud615","\ubbfc\uc8fc\ub178\ub3d9\ub2f9\uc774 \ucc3d\ub2f9\ud588\ub2e4","\ub178\ub3d9\xb7\uc9c4\ubcf4 \uc9c4\uc601\uc774 \uc6d0\ub0b4 \uc9c4\ucd9c\uc744 \ubaa9\ud45c\ub85c \uc815\ub2f9\uc744 \uc138\uc6e0\ub2e4. \ud55c\uad6d \uc815\uce58 \uc9c0\ud615\uc758 \ub2e4\ubcc0\ud654\uac00 \uc2dc\uc791\ub410\ub2e4.","\uc815\ucc45 \uc9c0\ud615\uc758 \ubcc0\ud654\ub294 \uaddc\uc81c\uc640 \uc0b0\uc5c5\uc758 \ubc29\ud5a5\uc744 \ubc14\uafc9\ub2c8\ub2e4.",B.I)
B.r=new A.o8(1,"shock")
B.Vp=new A.l(2000,1,31,"\ud56d\uacf5 \ucc38\uc0ac","\uc54c\ub798\uc2a4\uce74\ud56d\uacf5 261\ud3b8\uc774 \ucd94\ub77d\ud588\ub2e4","\uce98\ub9ac\ud3ec\ub2c8\uc544 \uc55e\ubc14\ub2e4\uc5d0\uc11c \uc5ec\uac1d\uae30\uac00 \ucd94\ub77d\ud574 \ud0d1\uc2b9\uc790 88\uba85 \uc804\uc6d0\uc774 \uc228\uc84c\ub2e4. \uc815\ube44 \uacb0\ud568\uc774 \uc6d0\uc778\uc73c\ub85c \uc9c0\ubaa9\ub410\ub2e4.","\uc548\uc804 \ube44\uc6a9\uc744 \uc544\ub080 \ub300\uac00\ub294 \ub298 \ub4a4\ub2a6\uac8c \uccad\uad6c\ub429\ub2c8\ub2e4.",B.r)
B.UM=new A.l(2000,2,3,"\ud1b5\uc2e0 \ube45\ub51c","\ubcf4\ub2e4\ud3f0\uc774 \ub9cc\ub124\uc2a4\ub9cc \uc778\uc218\uc5d0 \ud569\uc758\ud588\ub2e4","\uc5ed\ub300 \ucd5c\ub300 \uaddc\ubaa8\uc758 \uae30\uc5c5 \uc778\uc218\ub85c \uc720\ub7fd \ud1b5\uc2e0\uc5c5\uacc4\uac00 \uc7ac\ud3b8\ub410\ub2e4. \uc774\ub3d9\ud1b5\uc2e0 \uc131\uc7a5 \uae30\ub300\uac00 \uc778\uc218 \uad11\ud48d\uc744 \ubd88\ub800\ub2e4.","\uc131\uc7a5 \uc2a4\ud1a0\ub9ac\uac00 \ub728\uac70\uc6b8\uc218\ub85d \uc9c0\ubd88\ud55c \uac12\uc744 \ub418\uc9da\uc5b4 \ubcf4\uc138\uc694.",B.q)
B.Ve=new A.l(2000,2,12,"\uc2dc\ub300\uc758 \uc791\ubcc4","'\ud53c\ub108\uce20' \uc791\uac00 \ucc30\uc2a4 \uc290\uce20\uac00 \ubcc4\uc138\ud588\ub2e4","\uc2a4\ub204\ud53c\ub97c \uadf8\ub9b0 \ub9cc\ud654\uac00\uac00 \uc138\uc0c1\uc744 \ub5a0\ub098\uba70 \ubc18\uc138\uae30 \uc5f0\uc7ac\uac00 \ub9c9\uc744 \ub0b4\ub838\ub2e4. \ud55c \uc2dc\ub300\uc758 \ub300\uc911\ubb38\ud654\uac00 \uc800\ubb3c\uc5c8\ub2e4.","\uc624\ub798 \uc0ac\ub791\ubc1b\ub294 \ucf58\ud150\uce20\uc758 \uac00\uce58\ub97c \ub2e4\uc2dc \uc0dd\uac01\ud574 \ubcf4\uc138\uc694.",B.I)
B.Yj=new A.l(2000,2,17,"\uc81c\ud488 \ucd9c\uc2dc","\ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8\uac00 \uc708\ub3c4\uc6b0 2000\uc744 \ub0b4\ub1a8\ub2e4","\uae30\uc5c5\uc6a9 \uc6b4\uc601\uccb4\uc81c \uc2dc\uc7a5\uc744 \uaca8\ub0e5\ud55c \uc0c8 OS\uac00 \ucd9c\uc2dc\ub410\ub2e4. PC \uc18c\ud504\ud2b8\uc6e8\uc5b4 \uc9c0\ubc30\ub825\uc774 \ud55c\uce35 \uad73\uc5b4\uc84c\ub2e4.","\uc9c0\ub8e8\ud574 \ubcf4\uc774\ub294 \uae30\uc5c5\uc6a9 \uc18c\ud504\ud2b8\uc6e8\uc5b4\uac00 \ud604\uae08\uc744 \ub9cc\ub4ed\ub2c8\ub2e4.",B.w)
B.UJ=new A.l(2000,2,29,"\ub3c4\uc2dc \uc778\ud504\ub77c","\uc11c\uc6b8 \uc9c0\ud558\ucca0 7\ud638\uc120 \uc5f0\uc7a5 \uad6c\uac04\uc774 \uac1c\ud1b5\ud588\ub2e4","\uc218\ub3c4\uad8c \uc9c0\ud558\ucca0\ub9dd\uc774 \ud655\uc7a5\ub418\uba70 \ub3c4\uc2dc \uac1c\ubc1c \ucd95\uc774 \uc774\ub3d9\ud588\ub2e4. \uc778\ud504\ub77c \ud22c\uc790\ub294 \ubd80\ub3d9\uc0b0\uacfc \uc0c1\uad8c \uc9c0\ub3c4\ub97c \ubc14\uafbc\ub2e4.","\ub178\uc120\uc774 \uc9c0\ub098\ub294 \uacf3\uc5d0 \uc0ac\ub78c\uacfc \ub3c8\uc758 \ud750\ub984\uc774 \ub530\ub77c\ubd99\uc2b5\ub2c8\ub2e4.",B.I)
B.YC=new A.l(2000,3,4,"\ucf58\uc194 \ub300\uc804","\uc18c\ub2c8\uac00 \ud50c\ub808\uc774\uc2a4\ud14c\uc774\uc1582\ub97c \uc77c\ubcf8\uc5d0 \ubc1c\ub9e4\ud588\ub2e4","DVD \uc7ac\uc0dd\uae4c\uc9c0 \uac16\ucd98 \ucc28\uc138\ub300 \uac8c\uc784\uae30\uac00 \ucd9c\uc2dc\ub410\ub2e4. \uc18c\ub2c8\uac00 \uac70\uc2e4 \uc5d4\ud130\ud14c\uc778\uba3c\ud2b8\uc758 \uc911\uc2ec\uc744 \ub178\ub9b0\ub2e4.","\ud558\ub4dc\uc6e8\uc5b4\ubcf4\ub2e4 \uadf8 \uc704\uc5d0\uc11c \ub3cc\uc544\uac08 \uc0dd\ud0dc\uacc4\ub97c \ubcf4\uc138\uc694.",B.w)
B.YG=new A.l(2000,3,10,"\ub2f7\ucef4 \uc815\uc810","\ub098\uc2a4\ub2e5\uc774 \uc0ac\uc0c1 \ucd5c\uace0 5,048\uc744 \ucc0d\uc5c8\ub2e4","\ub2f7\ucef4 \uc5f4\ud48d \uc18d \uae30\uc220\uc8fc \uc9c0\uc218\uac00 \uc815\uc810\uc5d0 \uc62c\ub790\ub2e4. \uac19\uc740 \ub0a0 \ud55c\uad6d \ucf54\uc2a4\ub2e5\ub3c4 \uc0ac\uc0c1 \ucd5c\uace0\uc810\uc744 \uae30\ub85d\ud588\ub2e4.","\ubaa8\ub450\uac00 \ubd80\uc790\uac00 \ub41c \uac83 \uac19\uc740 \ub0a0, \ud604\uae08\uc758 \uac00\uce58\ub97c \ub5a0\uc62c\ub9ac\uc138\uc694.",B.q)
B.UK=new A.l(2000,3,13,"\ubc84\ube14 \uade0\uc5f4","\uae30\uc220\uc8fc \ub9e4\ub3c4\uc138\uac00 \uc2dc\uc791\ub410\ub2e4","\uace0\uc810 \uc9c1\ud6c4 \ub098\uc2a4\ub2e5\uc774 \ud754\ub4e4\ub9ac\uba70 \ucc28\uc775 \uc2e4\ud604 \ub9e4\ubb3c\uc774 \uc3df\uc544\uc84c\ub2e4. \ub05d\uc5c6\uc774 \uc624\ub97c \uac83 \uac19\ub358 \ub2f7\ucef4 \ub7a0\ub9ac\uc5d0 \uae08\uc774 \uac14\ub2e4.","\ucd94\uc138\uac00 \uaebe\uc774\ub294 \uccab \uc2e0\ud638\ub294 \ub298 \uc18c\uc74c\ucc98\ub7fc \ub4e4\ub9bd\ub2c8\ub2e4.",B.r)
B.a_0=new A.l(2000,3,18,"\ub300\ub9cc \uc815\uad8c\uad50\uccb4","\ucc9c\uc218\uc774\ubcdc\uc774 \ub300\ub9cc \ucd1d\ud1b5\uc5d0 \ub2f9\uc120\ub410\ub2e4","\uad6d\ubbfc\ub2f9\uc758 \ubc18\uc138\uae30 \uc9d1\uad8c\uc774 \ucc98\uc74c\uc73c\ub85c \ub9c9\uc744 \ub0b4\ub838\ub2e4. \uc591\uc548 \uad00\uacc4\uc758 \uae34\uc7a5\uc774 \uc0c8 \ubcc0\uc218\ub85c \ub5a0\uc62c\ub790\ub2e4.","\uc9c0\uc815\ud559\uc758 \uade0\uc5f4\uc740 \uacf5\uae09\ub9dd \uc9c0\ub3c4 \uc704\uc5d0 \uadf8\ub824\uc9d1\ub2c8\ub2e4.",B.q)
