B.VM=new A.l(2000,4,3,"\ubc18\ub3c5\uc810 \ucca0\ud1f4","\ubc95\uc6d0\uc774 MS\uc758 \ubc18\ub3c5\uc810\ubc95 \uc704\ubc18\uc744 \uc778\uc815\ud588\ub2e4","\uc7ad\uc2a8 \ud310\uc0ac\uac00 \ub9c8\uc774\ud06c\ub85c\uc18c\ud504\ud2b8\uc758 \uc2dc\uc7a5\uc9c0\ubc30\ub825 \ub0a8\uc6a9\uc744 \ud310\uacb0\ud588\ub2e4. \ube45\ud14c\ud06c \uaddc\uc81c\ub77c\ub294 \uc624\ub798\ub41c \ud654\ub450\uac00 \ubd88\ubd99\uc5c8\ub2e4.","\ub3c5\uc810\uc758 \ud798\uacfc \uaddc\uc81c\uc758 \uce7c\ub0a0\uc740 \ub298 \ud568\uaed8 \uc6c0\uc9c1\uc785\ub2c8\ub2e4.",B.r)
B.X8=new A.l(2000,4,13,"\ucd1d\uc120","\uc81c16\ub300 \uad6d\ud68c\uc758\uc6d0 \ucd1d\uc120\uac70\uac00 \uce58\ub7ec\uc84c\ub2e4","\uc5ec\uc18c\uc57c\ub300 \uad6c\ub3c4 \uc18d \uc815\uad6d\uc758 \uc8fc\ub3c4\uad8c \ub2e4\ud23c\uc774 \uc774\uc5b4\uc84c\ub2e4. \uc815\uce58 \uc77c\uc815\uc740 \uc815\ucc45\uacfc \uc608\uc0b0\uc758 \ubc29\ud5a5\uc744 \uac00\ub978\ub2e4.","\uc120\uac70 \uacb0\uacfc\ub294 \uaddc\uc81c \uc0b0\uc5c5\uc758 \ub0a0\uc528\ub97c \ubc14\uafc9\ub2c8\ub2e4.",B.q)
