B.Xq=new A.l(2001,6,11,"\uc0ac\ud615 \uc9d1\ud589","\uc624\ud074\ub77c\ud638\ub9c8 \ud3ed\ud0c4\ud14c\ub7ec\ubc94 \ub9e5\ubca0\uc774 \uc0ac\ud615","168\uba85\uc774 \uc228\uc9c4 \uc5f0\ubc29\uccad\uc0ac \ud3ed\ud0c4\ud14c\ub7ec\uc758 \ubc94\uc778\uc774 \ucc98\ud615\ub410\ub2e4.","\uc0ac\uc2e4\ub9cc \ub2f4\ub2f4\ud788 \uc804\ud569\ub2c8\ub2e4.",B.r)
